INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('diplomatic-36ccc47a-moex-00010', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-114-13504c0c', 'sub-diplomatic-36ccc47a-01', NULL, 'single_choice', '「身為偉大的候鳥族群，我們是活在北方凍土帶的環頸鴴……皮諾查下意識裡一直 認為，這些不肯回去的環頸鴴，已嚴重地觸犯祖先的規範，他們的行徑全然是他種 留鳥的習性，汙蔑了所有環頸鴴。但環頸鴴是和平的鳥類，縱使犯了這麼大的忤逆 罪，他們仍尊重這些『留鳥』的選擇。不過，部族的長老們憂心地意識到，這是明 顯的退化；他們若不繼續維持兩地來去的傳統，環頸鴴將無法和其他同型的鴴鷸科 水鳥競爭，未來有可能導致滅族的危機。過去，受到傳統教育的訓示，回到北方的 環頸鴴們也恥於談留鳥環頸鴴的問題。雖然他們在南方經常與留鳥一起相處，候鳥 們甚少細心探究過留鳥的形成原由。久而久之，每到春天後，就有一群留鳥滯留南 方，繁衍下一代。他們形成另一種傳統，對候鳥的遷徙反而覺得不可思議。」 有關上文形式與內涵，下列敘述何者正確？', '["文中具體展現了人類與動物的互動", "強調人類對「自然」已然造成某些改變與影響的事實", "作者在環頸鴴的行為與習性的基礎上賦予其「人格」，藉此揣測候鳥、留鳥之謎", "上文主旨在於藉由鳥類的視角演繹人類的價值觀，並非帶領讀者理解環頸鴴的 生態"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:24+00:00", "source_pdf_sha1": "3403830e86e7", "answer_pdf_sha1": "dbb86ff29ebd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00011', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-114-e6f33b51', 'sub-diplomatic-36ccc47a-02', NULL, 'essay', '美國川普總統於2025 年 4月對各國推出對等關稅。請回答下列問題：
美國的對等關稅稅率是否即為貿易理論中的最適關稅稅率？若為不
同，請詳細說明兩者各自如何訂定，以及其背後的目的各自為何？（請
注意在說明最適關稅稅率時，請以從量稅為例，並繪圖且輔以貿易理
論中相關的專有名詞）（15 分）
為抵制美國對等關稅，某國擬對美國商品課以報復性關稅。在排除世
界貿易組織（WorldTradeOrganization,WTO）相關規定等法律性和政
治性考量的情況下，請以經濟學理和實務的觀點評論之。（請至少提出
兩個觀點）（10分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:24+00:00", "source_pdf_sha1": "49f91d94d33d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "1105", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "國際經濟", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00012', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-114-e6f33b51', 'sub-diplomatic-36ccc47a-02', NULL, 'essay', '區域貿易協定在世界貿易組織（World Trade Organization,WTO）杜哈
