  ('diplomatic-36ccc47a-moex-00014', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-114-e6f33b51', 'sub-diplomatic-36ccc47a-02', NULL, 'single_choice', '根據大麥克指數，2024年1月份臺灣的大麥克價格是新臺幣72元，美國的大麥克價格是美金', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:24+00:00", "source_pdf_sha1": "49f91d94d33d", "answer_pdf_sha1": "06702a815132", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際經濟", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00015', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-114-e6f33b51', 'sub-diplomatic-36ccc47a-02', NULL, 'single_choice', '67元。如果真實的匯率是29.88NT$/US$，隱含新臺幣：', '["被高估57.5%", "被高估12.7%", "被低估57.5%", "被低估12.7%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:24+00:00", "source_pdf_sha1": "49f91d94d33d", "answer_pdf_sha1": "06702a815132", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際經濟", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00016', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-114-e6f33b51', 'sub-diplomatic-36ccc47a-02', NULL, 'single_choice', '根據Mundell（1963），如果一個國家資本於國際間是完全移動及貨幣當局未從事任何沖銷操作， 則 政策在 匯率制度下有最大的產出效果。', '["貨幣，浮動", "貨幣，固定", "財政，浮動", "財政，固定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:24+00:00", "source_pdf_sha1": "49f91d94d33d", "answer_pdf_sha1": "06702a815132", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際經濟", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00017', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-114-e6f33b51', 'sub-diplomatic-36ccc47a-02', NULL, 'single_choice', '不可能的三位一體（impossibletrinity）是在敘述一個國家不可能同時達成三個目標，這三個目標 不包括下列那一個？', '["資本自由移動", "穩定的匯率", "穩定的通貨膨脹率", "獨立自主的貨幣政策"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:24+00:00", "source_pdf_sha1": "49f91d94d33d", "answer_pdf_sha1": "06702a815132", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際經濟", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00018', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-114-e6f33b51', 'sub-diplomatic-36ccc47a-02', NULL, 'single_choice', '在管理浮動匯率制度下的「逆勢操作」，是指本國貨幣面臨貶值壓力時，中央銀行會在外匯市場：', '["拋售外匯", "買進外匯", "調高利率", "調低利率"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:24+00:00", "source_pdf_sha1": "49f91d94d33d", "answer_pdf_sha1": "06702a815132", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際經濟", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00019', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-114-e6f33b51', 'sub-diplomatic-36ccc47a-02', NULL, 'single_choice', '根據相對購買力平價學說，匯率變動率等於兩個國家的 差。', '["利率", "現貨市場匯率", "遠期市場匯率", "通貨膨脹率"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:24+00:00", "source_pdf_sha1": "49f91d94d33d", "answer_pdf_sha1": "06702a815132", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際經濟", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL)
